public class VendorServiceHelper {
    public static List<Service__c> getAllServices(){
        List<Service__c> retServices = [
            SELECT Id, Name, LastModifiedDate, CreatedById, OwnerId
            FROM Service__c
            ORDER BY Name
        ];
        return retServices;
    }
}

public static Service__c getServiceById(Id serviceId){
    Service__c retService = [SELECT Id, Name FROM Service__c WHERE Id = :serviceId LIMIT 1];

    return retService;
}


public static Service__c getServiceByName(String serviceName){
    Service__c retService = [SELECT Id, Name FROM Service__c WHERE Name = :serviceName LIMIT 1];

    return retService;
}

public static void createVendorServicesForSingleVendor(Id vendorAcctId, Set<Id> serviceIds){

    List<Vendor_Service__c> vendorServices = new List<Vendor_Service__c>();

    for(Id serviceId : serviceIds){
        Vendor_Service__c newVendorService = new Vendor_Service__c();
        newVendorService.Vendor__c = vendorAcctId;
        newVendorService.Service__c = serviceId;
        vendorServices.add(newVendorService);
    }

    insert vendorServices;
}

public static void createVendorServicesForSingleService(Set<Id> vendorAcctIds, Id serviceId){

    List<Vendor_Service__c> vendorServices = new List<Vendor_Service__c>();

    for(Id acctId : vendorAcctIds){
        Vendor_Service__c newVendorService = new Vendor_Service__c();
        newVendorService.Vendor__c = acctId;
