public class InvocableVendorServiceBuilder {

    @InvocableMethod
    public static void createVendorWithServices(List<FlowVendorServiceParams> vendorServiceParams){

        FlowVendorServiceParams params = vendorServiceParams[0];
        Set<Id> serviceIdSet = new Set<Id>();
        serviceIdSet.addAll(params.serviceIds);

        vendorServiceHelper.createVendorServicesForSingleVendor(params.acctId, serviceIdSet);
    }

    public class FlowVendorServiceParams{
        @InvocableVariable public Id acctId;
        @InvocableVariable public List<Id> serviceIds;
    }
}

trigger VendorServiceTrigger on Vendor_Service__c (before insert, before update) {
    List<Vendor_Service__c> vendorServices = trigger.new;
    Set<Id> vendorIds = new Set<Id>();
    Set<Id> serviceIds = new Set<Id>();
    for(Vendor_Service__c vendorService: vendorServices){
        vendorIds.add(vendorService.Vendor__c);
        serviceIds.add(vendorService.Service__c);
    }
    Map<Id,Account> vendorMap = new Map<Id,Account>([select id,name from account where id in :vendorIds]);
    Map<Id,Service__c> serviceMap = new Map<Id,Service__c>([select id,name from Service__c where id in :serviceIds]);
    for(Vendor_Service__c vendorService: vendorServices){
        vendorService.name = VendorServiceHelper.generateVendorServiceName(
            vendorMap.get(vendorService.Vendor__c).name,
            serviceMap.get(vendorService.Service__c).name
        );
    }
}

public class MgmtFeeBatch implements Schedulable {

    public Integer serviceYear;
    public Integer serviceMonth;

    public MgmtFeeBatch(Integer yr, Integer mo){
        this.serviceYear = yr;
        this.serviceMonth = mo;
    }

    public MgmtFeeBatch(){
        this.serviceYear = Date.today().year();
        this.serviceMonth = Date.today().month();
    }

    public void execute(SchedulableContext context){
        createMgmtFees();
    }
}

public void createMgmtFees(){
    Date serviceDate = Date.newInstance(serviceYear, serviceMonth, 1);

    List<Account> condos = [
        SELECT Id, Monthly_Mgmt_Fee__c,
            (SELECT Id, Service_Date__c, Fee__c FROM Mgmt_Fees__r)
        FROM Account
        WHERE Monthly_Mgmt_Fee__c != null
    ];

    Set<Mgmt_Fee__c> feesForInsert = new Set<Mgmt_Fee__c>();
    for(Account condo : condos){
        Set<Date> keys = new Set<Date>();

        for(Mgmt_Fee__c fee : condo.Mgmt_Fees__r){
            keys.add(fee.Service_Date__c);
        }

        if(!keys.contains(serviceDate)){
            Mgmt_Fee__c fee = new Mgmt_Fee__c(
                Service_Date__c = serviceDate,
                Fee__c = condo.Monthly_Mgmt_Fee__c,
                Association__c = condo.Id
            );
            feesForInsert.add(fee);
        }            
    }

    if(!feesForInsert.isEmpty()){
        List<Mgmt_Fee__c> feesForInsertList = new List<Mgmt_Fee__c>();
        feesForInsertList.addAll(feesForInsert);

        Database.insert(feesForInsertList);
    }
}

